// Guard: if no engagement data, skip
const engRaw = $('Fetch engagement summary').first().json;
const hotspotsRaw = $('Fetch quiz failure hotspots').first().json;
const personasRaw = $('Fetch all personas').first().json;

const topTopics     = engRaw?.top_topics ?? [];
const confTopics    = engRaw?.confusion_topics ?? [];
const saveCount     = engRaw?.save_count ?? 0;
const commentCount  = engRaw?.comment_count ?? 0;
const hotspots      = Array.isArray(hotspotsRaw) ? hotspotsRaw : [];
const personas      = Array.isArray(personasRaw) ? personasRaw : [];

if (topTopics.length === 0 && confTopics.length === 0 && hotspots.length === 0) {
  return []; // Nothing to report — skip
}

// Each persona gets a pulse post tailored to its style
const items = [];
for (const persona of personas) {
  const failedQuestions = hotspots.map(h => h.question).slice(0, 3).join('; ') || 'none recorded yet';
  const confusionList   = confTopics.join(', ') || 'none detected';
  const topList         = topTopics.join(', ')  || 'none yet';

  const systemPrompt = persona.system_prompt + `

You are writing a COMMUNITY PULSE post — a special update where you address your followers directly, like a creator going live to chat with their fanbase.

This post should feel personal and community-aware. Reference real data from the last 24 hours naturally.
Example openers:
- "okay I checked the stats and we need to talk..."
- "so I've been watching what you lot are struggling with and..."
- "community check-in time!!! here's what I'm seeing..."
- "alright your feedback has been LOUD so let me address this..."

Keep it SHORT (3-5 sentences), punchy, and in your signature voice.
Do NOT give a full lesson — this is the teaser/hook that makes them want to engage.
Return ONLY valid JSON with fields "title" and "body".`;

  const userPrompt = `Your community data from the last 24 hours:

📈 Topics your followers engaged with most: ${topList}
😕 Topics causing confusion (most human comments): ${confusionList}
❌ Quiz questions they're failing: ${failedQuestions}
💾 Saves: ${saveCount} | 💬 Comments: ${commentCount}

Write a community pulse post in YOUR voice that:
1. Acknowledges what's been happening in the community
2. Calls out the confusion/struggle areas in your signature style
3. Teases that you're working on content for them (without giving it away)

Return ONLY valid JSON with fields "title" and "body".`;

  items.push({
    json: {
      persona_id:    persona.id,
      persona_slug:  persona.slug,
      system_prompt: systemPrompt,
      user_prompt:   userPrompt,
      top_topics:    topTopics,
    }
  });
}

return items;

const llmResponse = $input.first().json;
const prev = $('Build pulse items').first().json;

const rawContent = llmResponse.choices?.[0]?.message?.content?.trim() ?? '';

let title = 'Community Pulse';
let body = rawContent;

try {
  const cleaned = rawContent.replace(/^```json?\s*/i, '').replace(/```\s*$/i, '').trim();
  const parsed = JSON.parse(cleaned);
  if (parsed.title) title = parsed.title;
  if (parsed.body)  body  = parsed.body;
} catch { /* use raw */ }

if (!body) return [];

// Find a representative material_id from the engagement data for FK reference
// Pulse posts are community-wide so we use null for material_id
return [{
  json: {
    persona_id:  prev.persona_id,
    persona_slug: prev.persona_slug,
    title,
    body,
  }
}];
